import {ueState} from "react";
import "./Home.css";

function Home() {
    const [file,setFile]=useState(null);

    function uploadword(event){
        const choose=event.target.file[0];
        setFile(choose)
    }

    return (
        <>
            <div className="heading">
                <h1>SMART RETAIL CHECKOUT AI</h1>
        </div>
    
        <div className="middle">
            <h2 style={{color:"lightgrey",textAlign:"center"}}>The system automatically detects the product price and calculates bill</h2>
        </div>

        <div className="upload">
            <input type="file"
             accept="image/*,video/*"
             onChange={uploadwork}
             />
            <p>Click here to upload files or videos</p>
        </div>
    </>
    
  )
}

export default Home;
